explanation: "<img src=\"https://corebtr-assets-production.s3.ap-south-1.amazonaws.com/question_explanation/2de1bd6f-5d6b-47d9-94b4-e9dc571d9fcb.jpg\" alt=\"Uploaded Image\">",
